package com.dataprocessing.grpc;

import io.grpc.stub.StreamObserver;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.io.*;
import java.nio.file.*;
import java.util.Map;
import java.util.UUID;
import java.util.concurrent.ConcurrentHashMap;

public class FileServiceImpl extends FileServiceGrpc.FileServiceImplBase {

    private static final Logger logger = LoggerFactory.getLogger(FileServiceImpl.class);
    private static final String UPLOAD_DIR = "uploads";
    private static final int CHUNK_SIZE = 64 * 1024; // 64KB chunks for streaming

    private final ConcurrentHashMap<String, Long> uploadProgress = new ConcurrentHashMap<>();
    private final DataProcessor dataProcessor;

    public FileServiceImpl() {
        this(new DefaultDataProcessor());
    }

    public FileServiceImpl(DataProcessor dataProcessor) {
        this.dataProcessor = dataProcessor;
        try {
            Files.createDirectories(Paths.get(UPLOAD_DIR));
        } catch (IOException e) {
            logger.error("Failed to create upload directory", e);
            throw new RuntimeException("Cannot initialize upload directory", e);
        }
    }

    @Override
    public StreamObserver<FileChunk> uploadFile(StreamObserver<UploadStatus> responseObserver) {
        return new StreamObserver<FileChunk>() {
            private String filename;
            private OutputStream outputStream;
            private long totalBytesReceived = 0;
            private final String uploadId = UUID.randomUUID().toString();

            @Override
            public void onNext(FileChunk chunk) {
                try {
                    if (outputStream == null) {
                        filename = sanitizeFilename(chunk.getFilename());
                        if (filename == null || filename.isEmpty()) {
                            throw new IllegalArgumentException("Invalid filename provided");
                        }
                        Path filePath = Paths.get(UPLOAD_DIR, uploadId + "_" + filename);
                        outputStream = new BufferedOutputStream(
                                new FileOutputStream(filePath.toFile()), 256 * 1024);
                        logger.info("Starting upload: {} (uploadId: {})", filename, uploadId);

                        if (chunk.getMetadataMap() != null) {
                            for (Map.Entry<String, String> entry : chunk.getMetadataMap().entrySet()) {
                                logger.debug("Upload metadata - {}: {}", entry.getKey(), entry.getValue());
                            }
                        }
                    }

                    byte[] data = chunk.getContent().toByteArray();
                    outputStream.write(data);
                    totalBytesReceived += data.length;
                    uploadProgress.put(uploadId, totalBytesReceived);

                    if (chunk.getTotalSize() > 0) {
                        double progress = (double) totalBytesReceived / chunk.getTotalSize() * 100;
                        logger.debug("Upload progress for {}: {:.1f}%", filename, progress);
                    }

                } catch (IOException e) {
                    logger.error("Error writing chunk for upload {}", uploadId, e);
                    cleanupStream();
                    responseObserver.onError(
                            io.grpc.Status.INTERNAL
                                    .withDescription("Failed to write file chunk: " + e.getMessage())
                                    .asRuntimeException());
                } catch (IllegalArgumentException e) {
                    logger.error("Invalid upload request", e);
                    responseObserver.onError(
                            io.grpc.Status.INVALID_ARGUMENT
                                    .withDescription(e.getMessage())
                                    .asRuntimeException());
                }
            }

            @Override
            public void onError(Throwable t) {
                logger.error("Upload stream error for {}", uploadId, t);
                cleanupStream();
                uploadProgress.remove(uploadId);
            }

            @Override
            public void onCompleted() {
                cleanupStream();
                uploadProgress.remove(uploadId);

                UploadStatus status = UploadStatus.newBuilder()
                        .setSuccess(true)
                        .setMessage("File uploaded successfully: " + filename)
                        .setBytesReceived(totalBytesReceived)
                        .build();

                logger.info("Upload completed: {} ({} bytes, uploadId: {})",
                        filename, totalBytesReceived, uploadId);

                responseObserver.onNext(status);
                responseObserver.onCompleted();
            }

            private void cleanupStream() {
                if (outputStream != null) {
                    try {
                        outputStream.flush();
                        outputStream.close();
                    } catch (IOException e) {
                        logger.warn("Error closing output stream for upload {}", uploadId, e);
                    }
                }
            }
        };
    }

    @Override
    public void downloadFile(FileRequest request, StreamObserver<FileChunk> responseObserver) {
        String filename = sanitizeFilename(request.getFilename());
        if (filename == null || filename.isEmpty()) {
            responseObserver.onError(
                    io.grpc.Status.INVALID_ARGUMENT
                            .withDescription("Invalid filename")
                            .asRuntimeException());
            return;
        }

        Path directory = Paths.get(UPLOAD_DIR);
        Path targetFile = null;

        try {
            // Find the file (may have uploadId prefix)
            try (DirectoryStream<Path> stream = Files.newDirectoryStream(directory, "*" + filename)) {
                for (Path entry : stream) {
                    targetFile = entry;
                    break;
                }
            }

            if (targetFile == null || !Files.exists(targetFile)) {
                responseObserver.onError(
                        io.grpc.Status.NOT_FOUND
                                .withDescription("File not found: " + filename)
                                .asRuntimeException());
                return;
            }

            long totalSize = Files.size(targetFile);
            logger.info("Starting download: {} ({} bytes)", filename, totalSize);

            try (InputStream inputStream = new BufferedInputStream(
                    new FileInputStream(targetFile.toFile()), 256 * 1024)) {

                byte[] buffer = new byte[CHUNK_SIZE];
                int bytesRead;
                long offset = 0;

                while ((bytesRead = inputStream.read(buffer)) != -1) {
                    FileChunk chunk = FileChunk.newBuilder()
                            .setFilename(filename)
                            .setContent(com.google.protobuf.ByteString.copyFrom(buffer, 0, bytesRead))
                            .setOffset(offset)
                            .setTotalSize(totalSize)
                            .build();

                    responseObserver.onNext(chunk);
                    offset += bytesRead;
                }
            }

            logger.info("Download completed: {}", filename);
            responseObserver.onCompleted();

        } catch (IOException e) {
            logger.error("Error during file download: {}", filename, e);
            responseObserver.onError(
                    io.grpc.Status.INTERNAL
                            .withDescription("Failed to read file: " + e.getMessage())
                            .asRuntimeException());
        }
    }

    @Override
    public StreamObserver<DataMessage> processData(StreamObserver<DataMessage> responseObserver) {
        return new StreamObserver<DataMessage>() {
            @Override
            public void onNext(DataMessage message) {
                try {
                    logger.debug("Processing data message: id={}, type={}, payload_size={}",
                            message.getId(), message.getType(), message.getPayload().size());

                    DataMessage result = dataProcessor.process(message);
                    responseObserver.onNext(result);

                } catch (Exception e) {
                    logger.error("Error processing data message: {}", message.getId(), e);
                    DataMessage errorResponse = DataMessage.newBuilder()
                            .setId(message.getId())
                            .setType("ERROR")
                            .setPayload(com.google.protobuf.ByteString.copyFromUtf8(e.getMessage()))
                            .putHeaders("error", e.getClass().getSimpleName())
                            .build();
                    responseObserver.onNext(errorResponse);
                }
            }

            @Override
            public void onError(Throwable t) {
                logger.error("Bidirectional stream error", t);
            }

            @Override
            public void onCompleted() {
                logger.info("Bidirectional stream completed");
                responseObserver.onCompleted();
            }
        };
    }

    private String sanitizeFilename(String filename) {
        if (filename == null) return null;
        // Remove path traversal characters
        String sanitized = filename.replaceAll("[^a-zA-Z0-9._-]", "_");
        if (sanitized.contains("..")) return null;
        return sanitized;
    }

    public Map<String, Long> getUploadProgress() {
        return new ConcurrentHashMap<>(uploadProgress);
    }
}

