package com.dataprocessing.grpc;

import com.google.protobuf.ByteString;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.nio.charset.StandardCharsets;
import java.security.MessageDigest;
import java.util.Map;

public class DefaultDataProcessor implements DataProcessor {

    private static final Logger logger = LoggerFactory.getLogger(DefaultDataProcessor.class);

    @Override
    public DataMessage process(DataMessage input) throws Exception {
        String type = input.getType();

        switch (type.toUpperCase()) {
            case "ECHO":
                return DataMessage.newBuilder()
                        .setId(input.getId())
                        .setType("ECHO_RESPONSE")
                        .setPayload(input.getPayload())
                        .putAllHeaders(input.getHeadersMap())
                        .putHeaders("processed", "true")
                        .build();

            case "CHECKSUM":
                MessageDigest digest = MessageDigest.getInstance("SHA-256");
                byte[] hash = digest.digest(input.getPayload().toByteArray());
                StringBuilder hexString = new StringBuilder();
                for (byte b : hash) {
                    hexString.append(String.format("%02x", b));
                }
                return DataMessage.newBuilder()
                        .setId(input.getId())
                        .setType("CHECKSUM_RESPONSE")
                        .setPayload(ByteString.copyFromUtf8(hexString.toString()))
                        .putHeaders("algorithm", "SHA-256")
                        .build();

            case "TRANSFORM":
                byte[] transformed = input.getPayload().toByteArray();
                String content = new String(transformed, StandardCharsets.UTF_8).toUpperCase();
                return DataMessage.newBuilder()
                        .setId(input.getId())
                        .setType("TRANSFORM_RESPONSE")
                        .setPayload(ByteString.copyFromUtf8(content))
                        .putHeaders("transformation", "uppercase")
                        .build();

            case "SIZE":
                long size = input.getPayload().size();
                return DataMessage.newBuilder()
                        .setId(input.getId())
                        .setType("SIZE_RESPONSE")
                        .setPayload(ByteString.copyFromUtf8(String.valueOf(size)))
                        .putHeaders("unit", "bytes")
                        .build();

            default:
                logger.warn("Unknown processing type: {}", type);
                return DataMessage.newBuilder()
                        .setId(input.getId())
                        .setType("UNKNOWN_TYPE_RESPONSE")
                        .setPayload(ByteString.copyFromUtf8("Unknown processing type: " + type))
                        .build();
        }
    }
}

